  ('dietitian-moex-11052', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有一團膳機構，其食物成本中新鮮材料占 80﹪，若食物成本占售價的 35﹪時，當售價100元時，新鮮材料可用多少 元？ 45元  35元  28元  20元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "0d2b7b701024", "answer_pdf_sha1": "b75a8902103e", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11053', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '儘量不以大容器而改以小容器貯存食物，以衛生觀點來看，其優點為何？ 好拿  中心溫度易降低  節省成本  增加工作效率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "0d2b7b701024", "answer_pdf_sha1": "b75a8902103e", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
